<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Falling Sand</title>
  <style>
    body {
      margin: 0;
      background-color: #121212;
      color: white;
      font-family: Arial, sans-serif;
      display: flex;
      justify-content: center;
      align-items: center;
      height: 100vh;
    }
    #container {
      text-align: center;
    }
    canvas {
      border: 1px solid #444;
      background-color: black;
    }
    #controls {
      margin-top: 20px;
    }
    button {
      margin: 5px;
      padding: 10px 20px;
      font-size: 16px;
      border: none;
      border-radius: 4px;
      background-color: #333;
      color: white;
      cursor: pointer;
      transition: background-color 0.2s;
    }
    button:hover {
      background-color: #555;
    }
    .active {
      background-color: #777 !important;
    }
  </style>
</head>
<body>
  <div id="container">
    <canvas id="sand" width="400" height="400"></canvas>
    <div id="controls">
      <button class="mat active" data-mat="sand">Sand</button>
      <button class="mat" data-mat="water">Water</button>
      <button class="mat" data-mat="wall">Wall</button>
      <button class="mat" data-mat="acid">Acid</button>
      <button class="mat" data-mat="empty">Erase</button>
      <button id="clear">Clear All</button>
    </div>
  </div>
  <script>
    const w = 80;
    const h = 80;
    const cellSize = 5;
    let grid = Array.from({ length: h }, () => Array(w).fill('empty'));
    let currentMat = 'sand';
    let painting = false;

    function isLiquid(mat) {
      return mat === 'water' || mat === 'acid';
    }

    function simulateStep() {
      const nextGrid = grid.map(row => row.slice());
      for (let y = h - 1; y >= 0; y--) {
        for (let x = 0; x < w; x++) {
          const mat = grid[y][x];
          if (mat === 'wall' || mat === 'empty') continue;

          let newX = x, newY = y;
          switch(mat) {
            case 'sand':
              handleSand(x, y, nextGrid);
              break;
            case 'water':
              handleWater(x, y, nextGrid);
              break;
            case 'acid':
              handleAcid(x, y, nextGrid);
              break;
          }
        }
      }
      grid = nextGrid;
    }

    function handleSand(x, y, nextGrid) {
      const belowY = y + 1;
      if (belowY >= h) return;

      const currentMat = grid[y][x];
      const belowMat = grid[belowY][x];

      if (belowMat === 'empty') {
        nextGrid[y][x] = 'empty';
        nextGrid[belowY][x] = currentMat;
        return;
      } else if (isLiquid(belowMat)) {
        nextGrid[y][x] = belowMat;
        nextGrid[belowY][x] = currentMat;
        return;
      }

      const directions = [[-1, 1], [1, 1]];
      for (let [dx, dy] of directions) {
        let nx = x + dx;
        let ny = y + dy;
        if (nx < 0 || nx >= w || ny < 0 || ny >= h) continue;
        const targetMat = grid[ny][nx];
        if (targetMat === 'empty' || isLiquid(targetMat)) {
          nextGrid[y][x] = 'empty';
          if (isLiquid(targetMat)) {
            nextGrid[nx][ny] = currentMat;
            nextGrid[x][y] = targetMat;
          } else {
            nextGrid[nx][ny] = currentMat;
          }
          return;
        }
      }
    }

    function handleWater(x, y, nextGrid) {
      const belowY = y + 1;
      if (belowY >= h) return;

      const currentMat = grid[y][x];
      const belowMat = grid[belowY][x];

      if (belowMat === 'empty') {
        nextGrid[y][x] = 'empty';
        nextGrid[belowY][x] = currentMat;
        return;
      } else if (isLiquid(belowMat)) {
        nextGrid[y][x] = belowMat;
        nextGrid[belowY][x] = currentMat;
        return;
      }

      const directions = [[-1, 0], [1, 0]];
      for (let [dx, dy] of directions) {
        let nx = x + dx;
        let ny = y;
        if (nx < 0 || nx >= w) continue;
        const targetMat = grid[ny][nx];
        if (targetMat === 'empty') {
          nextGrid[y][x] = 'empty';
          nextGrid[nx][y] = currentMat;
          return;
        }
      }
    }

    function handleAcid(x, y, nextGrid) {
      const belowY = y + 1;
      if (belowY < h) {
        const belowMat = grid[belowY][x];
        if (belowMat === 'empty') {
          nextGrid[y][x] = 'empty';
          nextGrid[belowY][x] = 'acid';
        } else if (isLiquid(belowMat)) {
          nextGrid[y][x] = belowMat;
          nextGrid[belowY][x] = 'acid';
        }
      }

      let movedDown = false;
      if (belowY < h && grid[belowY][x] !== 'empty' && !isLiquid(grid[belowY][x])) {
        const directions = [[-1, 0], [1, 0]];
        for (let [dx, dy] of directions) {
          let nx = x + dx;
          let ny = y;
          if (nx < 0 || nx >= w) continue;
          const targetMat = grid[ny][nx];
          if (targetMat === 'empty') {
            nextGrid[y][x] = 'empty';
            nextGrid[nx][y] = 'acid';
            movedDown = true;
            break;
          }
        }
      }

      let nx = x, ny = y;
      if (!movedDown && belowY < h) {
        const belowMat = grid[belowY][x];
        if (belowMat === 'empty' || isLiquid(belowMat)) {
          nx = x;
          ny = belowY;
        } else {
          for (let [dx, dy] of [[-1, 0], [1, 0]]) {
            let tx = x + dx;
            let ty = y;
            if (tx < 0 || tx >= w) continue;
            const targetMat = grid[ty][tx];
            if (targetMat === 'empty') {
              nx = tx;
              ny = ty;
              break;
            }
          }
        }
      }

      const dissolveDirs = [[0, 1], [-1, 0], [1, 0]];
      for (let [dx, dy] of dissolveDirs) {
        let tx = nx + dx;
        let ty = ny + dy;
        if (tx < 0 || tx >= w || ty < 0 || ty >= h) continue;
        const targetMat = grid[ty][tx];
        if (targetMat === 'sand' || targetMat === 'wall') {
          nextGrid[ty][tx] = 'empty';
        }
      }
    }

    function render() {
      const ctx = document.getElementById('sand').getContext('2d');
      ctx.clearRect(0, 0, 400, 400);
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          let mat = grid[y][x];
          let color;
          switch(mat) {
            case 'sand': color = '#FFD700'; break;
            case 'water': color = '#1E90FF'; break;
            case 'acid': color = '#008000'; break;
            case 'wall': color = '#808080'; break;
            default: color = 'black';
          }
          ctx.fillStyle = color;
          ctx.fillRect(x * cellSize, y * cellSize, cellSize, cellSize);
        }
      }
    }

    function getCellCoords(clientX, clientY) {
      const rect = document.getElementById('sand').getBoundingClientRect();
      let x = Math.floor((clientX - rect.left) / cellSize);
      let y = Math.floor((clientY - rect.top) / cellSize);
      return {x: Math.max(0, Math.min(w-1, x)), y: Math.max(0, Math.min(h-1, y))};
    }

    document.getElementById('sand').addEventListener('mousedown', (e) => {
      painting = true;
      const {x, y} = getCellCoords(e.clientX, e.clientY);
      set(x, y, currentMat);
    });

    document.getElementById('sand').addEventListener('mousemove', (e) => {
      if (!painting) return;
      const {x, y} = getCellCoords(e.clientX, e.clientY);
      set(x, y, currentMat);
    });

    document.getElementById('sand').addEventListener('mouseup', () => painting = false);
    document.getElementById('sand').addEventListener('mouseleave', () => painting = false);

    document.querySelectorAll('.mat').forEach(btn => {
      btn.addEventListener('click', () => {
        document.querySelectorAll('.mat').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        currentMat = btn.dataset.mat;
      });
    });

    document.getElementById('clear').addEventListener('click', () => {
      clear();
    });

    function set(x, y, mat) {
      if (x < 0 || x >= w || y < 0 || y >= h) return;
      grid[y][x] = mat;
    }

    function clear() {
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          grid[y][x] = 'empty';
        }
      }
    }

    let lastRenderTime = performance.now();
    const renderInterval = 1000 / 30;
    function animate() {
      requestAnimationFrame(animate);
      const now = performance.now();
      if (now - lastRenderTime >= renderInterval) {
        simulateStep();
        render();
        lastRenderTime = now;
      }
    }

    animate();

    window.sim = {
      w,
      h,
      tick(n) {
        for (let i = 0; i < n; i++) {
          simulateStep();
        }
      },
      get(x, y) {
        if (x < 0 || x >= w || y < 0 || y >= h) return 'empty';
        return grid[y][x];
      },
      set(x, y, mat) {
        set(x, y, mat);
      },
      clear() {
        clear();
      }
    };
  </script>
</body>
</html>
